# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session

app = Flask(__name__)
app.secret_key = 'your_secret_key'

@app.route('/update_profile', methods=['POST'])
def update_profile():
    data = request.get_json()
    
    # Extract new settings from the request
    email = data.get('email')
    password = data.get('password')
    two_factor_enabled = data.get('twoFactorEnabled')

    # Here you would typically validate and update the user's profile in your database
    # For demonstration, we'll just log the changes
    print(f"Updating profile for user: {session.get('user_id')}")
    if email:
        print(f"New Email: {email}")
    if password:
        print("Password updated")
    if two_factor_enabled is not None:
        print(f"2FA Enabled: {two_factor_enabled}")

    # Return a success response
    return jsonify({"message": "Profile updated successfully"}), 200

if __name__ == '__main__':
    app.run(debug=True)